670	func captureStdout(fn func() error) (string, error) {
671		old := os.Stdout
672		r, w, err := os.Pipe()
673		if err != nil {
674			return "", err
675		}
676		os.Stdout = w
677		defer func() { os.Stdout = old }()
678	
679		runErr := fn()
680		_ = w.Close()
681	
682		var buf bytes.Buffer
683		if _, err := io.Copy(&buf, r); err != nil {
684			return "", err
685		}
686		_ = r.Close()
687		return strings.TrimSpace(buf.String()), runErr
688	}
689	
690	func newSourceRepo(t *testing.T) (*git.Repository, billy.Filesystem) {
691		t.Helper()
692	
693		fs := memfs.New()
694		repo, err := git.Init(memory.NewStorage(), git.WithWorkTree(fs))
695		if err != nil {
696			t.Fatalf("init source repo: %v", err)
697		}
698	
699		return repo, fs
700	}
701	
702	func makeCommits(t *testing.T, repo *git.Repository, fs billy.Filesystem, count int) {
703		t.Helper()
704	
705		wt, err := repo.Worktree()
706		if err != nil {
707			t.Fatalf("open worktree: %v", err)
708		}
709	
710		for i := range count {
711			content := strings.Repeat(fmt.Sprintf("line %d %d\n", i, time.Now().UnixNano()), 24)
712			file, err := fs.Create("tracked.txt")
713			if err != nil {
714				t.Fatalf("create file: %v", err)
715			}
716			if _, err := io.WriteString(file, content); err != nil {
717				t.Fatalf("write file: %v", err)
718			}
719			if err := file.Close(); err != nil {
720				t.Fatalf("close file: %v", err)
721			}
722	
723			if _, err := wt.Add("tracked.txt"); err != nil {
724				t.Fatalf("add file: %v", err)
725			}
726	
727			_, err = wt.Commit(fmt.Sprintf("commit %d", i), &git.CommitOptions{
728				Author:    &objectSignature,
729				Committer: &objectSignature,
730			})
731			if err != nil {
732				t.Fatalf("commit: %v", err)
733			}
734		}
735	}
736	
737	var objectSignature = signature()
738	
739	func signature() object.Signature {
740		return object.Signature{
741			Name:  "test",
742			Email: "test@example.com",
743			When:  time.Unix(1, 0).UTC(),
744		}
745	}
746	
747	type smartHTTPRepoServer struct {
748		t        *testing.T
749		server   *httptest.Server
750		repo     *git.Repository
751		repoPath string
752	
753		// receivePackHook synthesizes the receive-pack response when set,
754		// bypassing the embedded ReceivePack handler. Used to simulate
755		// per-ref ng statuses from hostile targets.
756		receivePackHook func(*packp.UpdateRequests) *packp.ReportStatus
757	
758		mu           sync.Mutex
759		receivePacks int
760		thinCapable  bool
761	}
762	
763	func newSmartHTTPRepoServer(t *testing.T, repo *git.Repository) *smartHTTPRepoServer {
764		t.Helper()
765	
766		s := &smartHTTPRepoServer{
767			t:           t,
768			repo:        repo,
769			repoPath:    "/repo.git",
770			thinCapable: true,
771		}
772		s.server = httptest.NewServer(http.HandlerFunc(s.handle))
773		return s
774	}
775	
776	func (s *smartHTTPRepoServer) Close() {
777		s.server.Close()
778	}
779	
780	func (s *smartHTTPRepoServer) RepoURL() string {
781		return s.server.URL + s.repoPath
782	}
783	
784	func (s *smartHTTPRepoServer) Count(service string) int {
785		s.mu.Lock()
786		defer s.mu.Unlock()
787		if service == "git-receive-pack" {
788			return s.receivePacks
789		}
790		return 0
791	}
792	
793	func (s *smartHTTPRepoServer) handle(w http.ResponseWriter, r *http.Request) {
794		switch {
795		case r.Method == http.MethodGet && r.URL.Path == s.repoPath+"/info/refs":
796			s.handleInfoRefs(w, r)
797		case r.Method == http.MethodPost && r.URL.Path == s.repoPath+"/git-upload-pack":
798			s.handleUploadPack(w, r)
799		case r.Method == http.MethodPost && r.URL.Path == s.repoPath+"/git-receive-pack":
800			s.handleReceivePack(w, r)
801		default:
802			http.NotFound(w, r)
803		}
804	}
805	
806	func (s *smartHTTPRepoServer) handleInfoRefs(w http.ResponseWriter, r *http.Request) {
807		service := r.URL.Query().Get("service")
808		if service != transport.UploadPackService && service != transport.ReceivePackService {
809			http.Error(w, "missing service", http.StatusBadRequest)
810			return
811		}
812	
813		var buf bytes.Buffer
814		if err := transport.AdvertiseRefs(r.Context(), s.repo.Storer, &buf, service, false); err != nil {
815			http.Error(w, err.Error(), http.StatusInternalServerError)
816			return
817		}
818		if service == transport.ReceivePackService && s.thinCapable {
819			rewritten, err := rewriteReceivePackAdvertisement(buf.Bytes(), func(caps *capability.List) {
820				caps.Delete(capability.Capability("no-thin"))
821			})
822			if err != nil {
823				s.t.Fatalf("rewrite receive-pack advertisement: %v", err)
824			}
825			buf.Reset()
826			_, _ = buf.Write(rewritten)
827		}
828	
829		w.Header().Set("Content-Type", fmt.Sprintf("application/x-%s-advertisement", service))
830		if _, err := w.Write(buf.Bytes()); err != nil {
831			s.t.Fatalf("write advertised refs: %v", err)
832		}
833	}
834	
835	func rewriteReceivePackAdvertisement(data []byte, mutate func(*capability.List)) ([]byte, error) {
836		ar := &packp.AdvRefs{}
837		if err := ar.Decode(bytes.NewReader(data)); err == nil {
838			mutate(&ar.Capabilities)
839			var buf bytes.Buffer
840			if err := ar.Encode(&buf); err != nil {
841				return nil, err
842			}
843			return buf.Bytes(), nil
844		}
845	
846		rd := bytes.NewReader(data)
847		var smart packp.SmartReply
848		if err := smart.Decode(rd); err != nil {
849			return nil, err
850		}
851		ar = &packp.AdvRefs{}
852		if err := ar.Decode(rd); err != nil {
853			return nil, err
854		}
855		mutate(&ar.Capabilities)
856		var buf bytes.Buffer
857		if err := smart.Encode(&buf); err != nil {
858			return nil, err
859		}
860		if err := ar.Encode(&buf); err != nil {
861			return nil, err
862		}
863		return buf.Bytes(), nil
864	}
865	
866	func (s *smartHTTPRepoServer) handleUploadPack(w http.ResponseWriter, r *http.Request) {
867		var buf bytes.Buffer
868		wc := nopWriteCloser{&buf}
869	
870		err := transport.UploadPack(r.Context(), s.repo.Storer, r.Body, wc, &transport.UploadPackRequest{
871			StatelessRPC: true,
872		})
873		if err != nil {
874			http.Error(w, err.Error(), http.StatusInternalServerError)
875			return
876		}
877	
878		w.Header().Set("Content-Type", "application/x-git-upload-pack-result")
879		if _, err := w.Write(buf.Bytes()); err != nil {
880			s.t.Fatalf("write upload-pack response: %v", err)
881		}
882	}
883	
884	func (s *smartHTTPRepoServer) handleReceivePack(w http.ResponseWriter, r *http.Request) {
885		s.mu.Lock()
886		s.receivePacks++
887		s.mu.Unlock()
888	
889		if s.receivePackHook != nil {
890			body, err := io.ReadAll(r.Body)
891			if err != nil {
892				http.Error(w, err.Error(), http.StatusBadRequest)
893				return
894			}
895			req := &packp.UpdateRequests{}
896			if err := req.Decode(bytes.NewReader(body)); err != nil {
897				http.Error(w, err.Error(), http.StatusBadRequest)
898				return
899			}
900			report := s.receivePackHook(req)
901			// Wrap the report in sideband framing when negotiated, mirroring
902			// what transport.ReceivePack writes; the client's demuxer otherwise
903			// fails on raw report-status pkt-lines.
904			var buf bytes.Buffer
905			var writer io.Writer = &buf
906			useSideband := false
907			// Mirrors the syncer test server's sideband-wrap: no-progress
908			// turns off the wrapping even if a sideband cap is advertised.
909			if !req.Capabilities.Supports(capability.NoProgress) {
910				switch {
911				case req.Capabilities.Supports(capability.Sideband64k):
912					writer = sideband.NewMuxer(sideband.Sideband64k, &buf)
913					useSideband = true
914				case req.Capabilities.Supports(capability.Sideband):
915					writer = sideband.NewMuxer(sideband.Sideband, &buf)
916					useSideband = true
917				}
918			}
919			if err := report.Encode(nopWriteCloser{writer}); err != nil {
920				http.Error(w, err.Error(), http.StatusInternalServerError)
921				return
922			}
923			if useSideband {
924				_ = pktline.WriteFlush(&buf)
925			}
926			w.Header().Set("Content-Type", "application/x-git-receive-pack-result")
927			if _, err := w.Write(buf.Bytes()); err != nil {
928				s.t.Fatalf("write receive-pack hook response: %v", err)
929			}
930			return
931		}
932	
933		var buf bytes.Buffer
934		wc := nopWriteCloser{&buf}
935	
936		err := transport.ReceivePack(r.Context(), s.repo.Storer, r.Body, wc, &transport.ReceivePackRequest{
937			StatelessRPC: true,
938		})
939	
940		w.Header().Set("Content-Type", "application/x-git-receive-pack-result")
941		if buf.Len() > 0 {
942			if _, err := w.Write(buf.Bytes()); err != nil {
943				s.t.Fatalf("write receive-pack response: %v", err)
944			}
945		}
946		if err != nil {
947			return
948		}
949	}
950	
951	// nopWriteCloser wraps an io.Writer to satisfy io.WriteCloser.
952	type nopWriteCloser struct{ io.Writer }
953	
954	func (nopWriteCloser) Close() error { return nil }
955

