			http.Redirect(w, r, sourceServer.server.URL+r.URL.Path+"?"+r.URL.RawQuery, http.StatusTemporaryRedirect)
		case r.Method == http.MethodPost:
			http.Error(w, "entry domain rejects packs", http.StatusMethodNotAllowed)
